123	func updateDeploymentArgs(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) {
124		config := trustManager.Spec.TrustManagerConfig
125		trustNamespace := getTrustNamespace(trustManager)
126	
127		args := []string{
128			fmt.Sprintf("--log-format=%s", config.LogFormat),
129			fmt.Sprintf("--log-level=%d", config.LogLevel),
130			"--metrics-port=9402",
131			"--readiness-probe-port=6060",
132			"--readiness-probe-path=/readyz",
133			"--leader-elect=true",
134			"--leader-election-lease-duration=15s",
135			"--leader-election-renew-deadline=10s",
136			fmt.Sprintf("--trust-namespace=%s", trustNamespace),
137			"--webhook-host=0.0.0.0",
138			"--webhook-port=6443",
139			"--webhook-certificate-dir=/tls",
140		}
141	
142		if secretTargetsEnabled(config.SecretTargets) {
143			args = append(args, "--secret-targets-enabled=true")
144		}
145	
146		if config.FilterExpiredCertificates == v1alpha1.FilterExpiredCertificatesPolicyEnabled {
147			args = append(args, "--filter-expired-certificates=true")
148		}
149	
150		if defaultCAPackageEnabled(config.DefaultCAPackage) {
151			args = append(args, fmt.Sprintf("--default-package-location=%s", defaultCAPackageLocation))
152		}
153	
154		for i, container := range deployment.Spec.Template.Spec.Containers {
155			if container.Name == trustManagerContainerName {
156				deployment.Spec.Template.Spec.Containers[i].Args = args
157			}
158		}
159	}
