597	func (r *Reconciler) validatePEMData(pemData string) error {
598		if pemData == "" {
599			return fmt.Errorf("PEM data is empty")
600		}
601	
602		// Parse the first certificate from PEM data
603		block, _ := pem.Decode([]byte(pemData))
604		if block == nil {
605			return fmt.Errorf("no valid PEM data found")
606		}
607	
608		if block.Type != "CERTIFICATE" {
609			return fmt.Errorf("PEM block is not a certificate, found: %s", block.Type)
610		}
611	
612		cert, err := x509.ParseCertificate(block.Bytes)
613		if err != nil {
614			return fmt.Errorf("failed to parse certificate: %w", err)
615		}
616	
617		if !cert.BasicConstraintsValid {
618			return fmt.Errorf("certificate does not have valid Basic Constraints extension")
619		}
620	
621		if !cert.IsCA {
622			return fmt.Errorf("certificate is not a CA certificate")
623		}
624	
625		// Check Key Usage for certificate signing
626		if cert.KeyUsage&x509.KeyUsageCertSign == 0 {
627			return fmt.Errorf("certificate does not have Certificate Sign key usage")
628		}
629	
630		return nil
631	}
